<template><div class="h-[calc(100vh-3.5rem)] overflow-y-auto p-4 space-y-4"><div class="flex items-center gap-3"><div><h1 class="text-base font-semibold text-gray-100">Portfolio Lab</h1><p class="text-[10px] text-gray-600">correlação · risco · drawdown · contribuição marginal</p></div><div class="flex-1"/><form @submit.prevent="load" class="flex gap-2"><input v-model="input" class="form-input !py-1.5 text-xs w-64 uppercase"/><select v-model="years" class="form-select !py-1.5 text-xs"><option :value="1">1 ano</option><option :value="3">3 anos</option><option :value="5">5 anos</option></select><button class="btn-secondary !py-1.5 text-xs">Calcular</button></form></div><div v-if="error" class="card p-3 text-xs text-red-400">{{error}}</div><template v-if="d"><div class="grid grid-cols-2 md:grid-cols-4 gap-2"><div v-for="x in cards" :key="x.l" class="metric-card"><span class="metric-label">{{x.l}}</span><span class="metric-value text-gray-100">{{x.v}}</span></div></div><div class="grid grid-cols-1 xl:grid-cols-2 gap-4"><div class="card p-4"><div class="title">Correlação</div><div ref="heatmap" class="h-80"/></div><div class="card p-4"><div class="title">Contribuição de risco · pesos iguais</div><div ref="risk" class="h-80"/></div></div><div class="card p-4 overflow-x-auto"><table class="w-full text-xs font-mono"><thead><tr class="text-gray-600"><th class="text-left">Ativo</th><th>Retorno anual</th><th>Vol anual</th><th>Sharpe</th><th>Max DD</th></tr></thead><tbody><tr v-for="m in d.metrics" :key="m.symbol" class="border-t border-surface-600"><td class="py-2 text-gray-200">{{m.symbol}}</td><td class="text-center">{{pct(m.return_ann_pct)}}</td><td class="text-center">{{pct(m.vol_ann_pct)}}</td><td class="text-center">{{m.sharpe?.toFixed(2)}}</td><td class="text-center text-red-400">{{pct(m.max_drawdown_pct)}}</td></tr></tbody></table></div><p class="text-[10px] text-gray-600">{{d.methodology}}</p></template></div></template>
<script setup>import{ref,computed,nextTick,onMounted}from'vue';import{runPortfolioLab}from'@/api/client.js';const input=ref('BTC-USD,^GSPC,GC=F,TLT'),years=ref(3),d=ref(null),error=ref(null),heatmap=ref(null),risk=ref(null),pct=v=>v==null?'—':`${Number(v).toFixed(2)}%`;const cards=computed(()=>d.value?[{l:'Retorno anual',v:pct(d.value.portfolio.return_ann_pct)},{l:'Volatilidade',v:pct(d.value.portfolio.vol_ann_pct)},{l:'Sharpe',v:d.value.portfolio.sharpe.toFixed(2)},{l:'Max drawdown',v:pct(d.value.portfolio.max_drawdown_pct)}]:[]);async function draw(){const P=(await import('plotly.js-dist-min')).default;await nextTick();const l={template:'plotly_dark',paper_bgcolor:'#000',plot_bgcolor:'#080808',font:{color:'#aaa',size:10},height:320,margin:{t:10,r:20,b:50,l:55}};P.newPlot(heatmap.value,[{type:'heatmap',x:d.value.symbols,y:d.value.symbols,z:d.value.correlation,zmin:-1,zmax:1,colorscale:'RdBu',reversescale:true}],l,{responsive:true,displayModeBar:false});P.newPlot(risk.value,[{type:'bar',x:d.value.symbols,y:d.value.portfolio.risk_contribution_pct,marker:{color:'#f5c518'}}],{...l,yaxis:{ticksuffix:'%'}},{responsive:true,displayModeBar:false})}async function load(){try{d.value=(await runPortfolioLab(input.value.split(','),years.value)).data;error.value=null;await draw()}catch(e){error.value=e.response?.data?.error||e.message}}onMounted(load)</script><style scoped>.title{@apply text-[10px] text-gray-500 uppercase mb-2}</style>
